1	#!/usr/bin/env node
2	/**
3	 * P2 — 并行 TTS 合成
4	 *
5	 * 读取 chunks.json，对每个 pending chunk 调用 Fish TTS，输出独立 WAV。
6	 * 支持指定单个 chunk 重做（--chunk <id>）。
7	 *
8	 * Usage:
9	 *   node scripts/p2-synth.js --chunks <chunks.json> --outdir <dir>
10	 *   node scripts/p2-synth.js --chunks <chunks.json> --outdir <dir> --chunk shot02_chunk01
11	 */
12	
13	const fs = require("fs");
14	const path = require("path");
15	const { execSync } = require("child_process");
16	const { trace } = require("./trace");
17	
18	// --- 配置（env 优先 → config.json → 默认值）---
19	const _p2Defaults = { concurrency: 3, max_retries: 3, default_speed: 1.0, model: "s1" };
20	try {
21	  const _cfg = JSON.parse(require("fs").readFileSync(require("path").join(__dirname, "..", ".harness", "config.json"), "utf-8"));
22	  if (_cfg.p2) Object.assign(_p2Defaults, _cfg.p2);
23	} catch {}
24	
25	const TTS_API_URL = "https://api.fish.audio/v1/tts";
26	const TTS_API_KEY = process.env.FISH_TTS_KEY;
27	if (!TTS_API_KEY) {
28	  console.error("ERROR: FISH_TTS_KEY environment variable is required");
29	  process.exit(1);
30	}
31	const TTS_MODEL = process.env.FISH_TTS_MODEL || _p2Defaults.model;
32	const TTS_REFERENCE_ID = process.env.FISH_TTS_REFERENCE_ID || "";
33	const DEFAULT_SPEED = parseFloat(process.env.TTS_SPEED || String(_p2Defaults.default_speed));
34	const CONCURRENCY = _p2Defaults.concurrency;
35	
36	// --- 参数解析 ---
37	const args = process.argv.slice(2);
38	let chunksPath = "";
39	let outdir = "";
40	let targetChunk = "";
41	let speed = DEFAULT_SPEED;
42	let tracePath = "";
43	
44	for (let i = 0; i < args.length; i++) {
45	  if (args[i] === "--chunks" && args[i + 1]) chunksPath = args[++i];
46	  else if (args[i] === "--outdir" && args[i + 1]) outdir = args[++i];
47	  else if (args[i] === "--chunk" && args[i + 1]) targetChunk = args[++i];
48	  else if (args[i] === "--speed" && args[i + 1]) speed = parseFloat(args[++i]);
49	  else if (args[i] === "--trace" && args[i + 1]) tracePath = args[++i];
50	}
51	
52	if (!chunksPath || !outdir) {
53	  console.error(
54	    "Usage: node p2-synth.js --chunks <chunks.json> --outdir <dir> [--chunk <id>] [--speed 1.15]"
55	  );
56	  process.exit(1);
57	}
58	
59	// =============================================================
60	// TTS API — standard https.request (proxy via HTTPS_PROXY env)
61	// =============================================================
62	
63	function callTTS(text) {
64	  return new Promise((resolve, reject) => {
65	    const https = require("https");
66	    const url = new URL(TTS_API_URL);
67	    const payload = { text };
68	    if (TTS_REFERENCE_ID) payload.reference_id = TTS_REFERENCE_ID;
69	    const body = JSON.stringify(payload);
70	
71	    const req = https.request(
72	      {
73	        hostname: url.hostname,
74	        port: 443,
75	        path: url.pathname,
76	        method: "POST",
77	        headers: {
78	          "Content-Type": "application/json",
79	          "Authorization": `Bearer ${TTS_API_KEY}`,
80	          "model": TTS_MODEL,
81	          "Content-Length": Buffer.byteLength(body),
82	        },
83	        timeout: 120000,
84	      },
85	      (res) => {
86	        const chunks = [];
87	        res.on("data", (chunk) => chunks.push(chunk));
88	        res.on("end", () => {
89	          if (res.statusCode !== 200) {
90	            reject(new Error(`TTS API ${res.statusCode}: ${Buffer.concat(chunks).toString().slice(0, 200)}`));
91	          } else {
92	            resolve(Buffer.concat(chunks));
93	          }
94	        });
95	      }
96	    );
97	
98	    req.on("error", reject);
99	    req.on("timeout", () => {
100	      req.destroy();
101	      reject(new Error("TTS API timeout"));
102	    });
103	    req.write(body);
104	    req.end();
105	  });
106	}
107	
108	function applySpeed(inputPath, outputPath, tempo) {
109	  execSync(
110	    `ffmpeg -y -i "${inputPath}" -filter:a "atempo=${tempo}" -ar 44100 "${outputPath}" 2>/dev/null`
111	  );
112	}
113	
114	function getAudioDuration(filePath) {
115	  const out = execSync(
116	    `ffprobe -v quiet -show_entries format=duration -of csv=p=0 "${filePath}"`,
117	    { encoding: "utf-8" }
118	  );
119	  return parseFloat(out.trim());
120	}
121	
122	// =============================================================
123	// 并行控制
124	// =============================================================
125	
126	async function processChunk(chunk) {
127	  const mp3Path = path.join(outdir, `${chunk.id}.mp3`);
128	  const wavPath = path.join(outdir, `${chunk.id}.wav`);
129	
130	  console.log(`  [TTS] ${chunk.id}: "${chunk.text_normalized.slice(0, 40)}..."`);
131	
132	  const t0 = Date.now();
133	  if (tracePath) trace(tracePath, { chunk: chunk.id, phase: "p2", event: "start" });
134	
135	  // 重试 3 次
136	  let lastErr;
137	  for (let attempt = 1; attempt <= 3; attempt++) {
138	    try {
139	      const audioBuffer = await callTTS(chunk.text_normalized);
140	      fs.writeFileSync(mp3Path, audioBuffer);
141	      applySpeed(mp3Path, wavPath, speed);
142	      fs.unlinkSync(mp3Path);
143	
144	      const duration = getAudioDuration(wavPath);
145	      console.log(`    → ${chunk.id}.wav (${duration.toFixed(2)}s)`);
146	
147	      if (tracePath) trace(tracePath, { chunk: chunk.id, phase: "p2", event: "done", duration_ms: Date.now() - t0 });
148	      return { id: chunk.id, duration_s: Math.round(duration * 1000) / 1000, file: `${chunk.id}.wav`, status: "synth_done" };
149	    } catch (e) {
150	      lastErr = e;
151	      console.error(`    [RETRY ${attempt}/3] ${chunk.id}: ${e.message}`);
152	      if (attempt < 3) await new Promise((r) => setTimeout(r, 1000 * Math.pow(2, attempt - 1)));
153	    }
154	  }
155	
156	  console.error(`    [FAIL] ${chunk.id}: ${lastErr.message}`);
157	  if (tracePath) trace(tracePath, { chunk: chunk.id, phase: "p2", event: "done", duration_ms: Date.now() - t0, error: lastErr.message });
158	  return { id: chunk.id, duration_s: 0, file: null, status: "synth_failed", error: lastErr.message };
159	}
160	
161	async function runWithConcurrency(items, fn, limit) {
162	  const results = [];
163	  let idx = 0;
164	
165	  async function worker() {
166	    while (idx < items.length) {
167	      const i = idx++;
168	      results[i] = await fn(items[i]);
169	    }
170	  }
171	
172	  const workers = Array.from({ length: Math.min(limit, items.length) }, () => worker());
173	  await Promise.all(workers);
174	  return results;
175	}
176	
177	// =============================================================
178	// Main
179	// =============================================================
180	
181	async function main() {
182	  const chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
183	  fs.mkdirSync(outdir, { recursive: true });
184	
185	  // 过滤要处理的 chunks
186	  let toProcess;
187	  if (targetChunk) {
188	    toProcess = chunks.filter((c) => c.id === targetChunk);
189	    if (toProcess.length === 0) {
190	      console.error(`Chunk "${targetChunk}" not found`);
191	      process.exit(1);
192	    }
193	  } else {
194	    toProcess = chunks.filter((c) => c.status === "pending" || c.status === "synth_failed");
195	  }
196	
197	  console.log(`=== P2: Synthesizing ${toProcess.length} chunk(s), concurrency=${CONCURRENCY}, speed=${speed}x ===\n`);
198	
199	  const results = await runWithConcurrency(toProcess, processChunk, CONCURRENCY);
200	
201	  // 更新 chunks.json 的 status
202	  for (const r of results) {
203	    const chunk = chunks.find((c) => c.id === r.id);
204	    if (chunk) {
205	      chunk.status = r.status;
206	      chunk.duration_s = r.duration_s;
207	      chunk.file = r.file;
208	      if (r.error) chunk.error = r.error;
209	    }
210	  }
211	
212	  fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
213	
214	  // 摘要
215	  const ok = results.filter((r) => r.status === "synth_done").length;
216	  const fail = results.filter((r) => r.status === "synth_failed").length;
217	  const totalDur = results.reduce((s, r) => s + r.duration_s, 0);
218	
219	  console.log(`\n=== Done: ${ok} ok, ${fail} failed, total ${totalDur.toFixed(1)}s ===`);
220	  if (fail > 0) process.exit(1);
221	}
222	
223	main().catch((e) => {
224	  console.error(e);
225	  process.exit(1);
226	});
