const fs = require('fs');
const lines = fs.readFileSync('$TRANSCRIPT_CSV', 'utf-8').trim().split('\n').slice(1);
const data = lines.map(l => {
  const i1 = l.indexOf(',');
  const i2 = l.indexOf(',', i1 + 1);
  return { group: l.slice(0, i1), run: l.slice(i1+1, i2), transcript: l.slice(i2+1) };
});

// 关键词及其常见误识别
const checks = [
  { keyword: 'Ollama', patterns: [/ollama/i, /欧拉马/i, /哦拉马/i, /奥拉马/i] },
  { keyword: 'RAG',    patterns: [/RAG/i, /rag/i, /R\.A\.G/i] },
  { keyword: 'Mac',    patterns: [/mac/i, /麦克/i] },
];

const groups = [...new Set(data.map(d => d.group))];

for (const check of checks) {
  console.log('关键词: ' + check.keyword);
  console.log('-'.repeat(50));
  for (const g of groups) {
    const rows = data.filter(d => d.group === g);
    for (const r of rows) {
      const matched = check.patterns.find(p => p.test(r.transcript));
      const status = matched ? '✓ 识别到' : '✗ 未识别';
      // 找到匹配的文本片段
      let excerpt = '';
      if (matched) {
        const m = r.transcript.match(matched);
        if (m) {
          const start = Math.max(0, m.index - 5);
          const end = Math.min(r.transcript.length, m.index + m[0].length + 5);
          excerpt = '\"...' + r.transcript.slice(start, end) + '...\"';
        }
      }
      console.log('  ' + g + '/' + r.run + ': ' + status + (excerpt ? '  ' + excerpt : ''));
    }
  }
  console.log('');
}

// 汇总
console.log('=== 汇总 ===');
for (const check of checks) {
  let total = 0, found = 0;
  for (const d of data) {
    total++;
    if (check.patterns.some(p => p.test(d.transcript))) found++;
  }
  console.log(check.keyword + ': ' + found + '/' + total + ' 识别正确 (' + (found/total*100).toFixed(0) + '%)');
}

console.log('');
console.log('转写结果: $TRANSCRIPT_CSV');
"

