#!/bin/bash
# 对 A/B 测试生成的音频做 WhisperX 转写 + 关键词检测
#
# 自动启动/复用 P3 server，转写全部 WAV，检查 Ollama/RAG 发音
#
# Usage: bash test/transcribe-ab-test.sh

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_DIR="$(dirname "$SCRIPT_DIR")"
ABTEST_DIR="$REPO_DIR/output/param-ab-test"
PORT=5555
SERVER_URL="http://127.0.0.1:$PORT"
OWN_SERVER=false

if [ ! -d "$ABTEST_DIR" ]; then
  echo "ERROR: $ABTEST_DIR not found. Run tts-param-ab-test.sh first." >&2
  exit 1
fi

# --- 检查/启动 P3 server ---
health_ok() {
  local resp
  resp=$(curl -s --max-time 2 "$SERVER_URL/health" 2>/dev/null) || return 1
  echo "$resp" | grep -q "ok"
}

if health_ok; then
  echo "P3 server already running on port $PORT"
else
  echo "Starting P3 server (model loading may take ~60s)..."
  P3_LOG="$ABTEST_DIR/p3-server.log"
  python3 "$REPO_DIR/scripts/p3-transcribe.py" --server --port $PORT > "$P3_LOG" 2>&1 &
  P3_PID=$!
  OWN_SERVER=true

  # 等待 READY — 模型加载需要时间
  for i in $(seq 1 120); do
    if health_ok; then
      echo "P3 server ready (pid=$P3_PID)"
      break
    fi
    if ! kill -0 $P3_PID 2>/dev/null; then
      echo "ERROR: P3 server process died" >&2
      exit 1
    fi
    if [ "$i" -eq 120 ]; then
      echo "ERROR: P3 server failed to start in 120s" >&2
      kill $P3_PID 2>/dev/null || true
      exit 1
    fi
    sleep 1
  done
fi

cleanup() {
  if $OWN_SERVER && [ -n "${P3_PID:-}" ]; then
    echo ""
    echo "Stopping P3 server (pid=$P3_PID)..."
    kill $P3_PID 2>/dev/null || true
    wait $P3_PID 2>/dev/null || true
  fi
}
trap cleanup EXIT

# --- 转写所有 WAV ---
echo ""
echo "============================================"
echo " 批量转写 A/B 测试音频"
echo "============================================"

TRANSCRIPT_CSV="$ABTEST_DIR/transcripts.csv"
echo "group,run,transcript" > "$TRANSCRIPT_CSV"

KEYWORDS=("Ollama" "RAG" "Mac")

for group_dir in "$ABTEST_DIR"/A_* "$ABTEST_DIR"/B_* "$ABTEST_DIR"/C_*; do
  [ -d "$group_dir" ] || continue
  group=$(basename "$group_dir")
  echo ""
  echo "--- 组 $group ---"

  for wav in "$group_dir"/run*.wav; do
    [ -f "$wav" ] || continue
    run=$(basename "$wav" .wav)
    abs_wav=$(cd "$(dirname "$wav")" && pwd)/$(basename "$wav")

    printf "  %s ... " "$run"

    result=$(curl -s --max-time 120 -X POST "$SERVER_URL/transcribe" \
      -H "Content-Type: application/json" \
      -d "$(jq -n --arg ap "$abs_wav" --arg cid "${group}_${run}" \
        '{audio_path: $ap, chunk_id: $cid, text: "", text_normalized: ""}')")

    transcript=$(echo "$result" | jq -r '.full_transcribed_text // "ERROR"')
    echo "$transcript"

    # CSV（转义逗号）
    escaped=$(echo "$transcript" | sed 's/,/，/g')
    echo "$group,$run,$escaped" >> "$TRANSCRIPT_CSV"
  done
done

# --- 关键词检测报告 ---
echo ""
echo "============================================"
echo " 关键词发音检测"
echo "============================================"
echo ""

